CREATE OR REPLACE FUNCTION OFSERM.MR_Account_Attribute_Shareholding_Percent_Multiplication(
    P_V_BATCH_ID         VARCHAR2,
    P_V_MIS_DATE         VARCHAR2,
    P_V_RUN_ID           VARCHAR2,
    P_V_PROCESS_ID       VARCHAR2,
    P_V_RUN_EXECUTION_ID VARCHAR2,
    P_N_RUN_SKEY         VARCHAR2,
    P_V_TASK_ID          VARCHAR2
) RETURN VARCHAR2 AUTHID CURRENT_USER AS

    ld_mis_date   DATE          := TO_DATE(P_V_MIS_DATE, 'YYYYMMDD');
    ln_mis_date   NUMBER        := TO_NUMBER(P_V_MIS_DATE);
    ln_run_skey   NUMBER(5)     := TO_NUMBER(SUBSTR(P_N_RUN_SKEY, 8, LENGTH(P_N_RUN_SKEY)));
    lv_run_id     VARCHAR2(64)  := SUBSTR(P_V_RUN_ID, 8, LENGTH(P_V_RUN_ID));

BEGIN

    MERGE  INTO FCT_MARKET_RISK_EXPOSURES TT USING (   SELECT * FROM (  SELECT  /*+ PARALLEL(4) */ FCT_MARKET_RISK_EXPOSURES.N_ACCT_SKEY,FCT_MARKET_RISK_EXPOSURES.N_RUN_SKEY,FCT_MARKET_RISK_EXPOSURES.N_GAAP_SKEY,FCT_MARKET_RISK_EXPOSURES.N_MIS_DATE_SKEY,(FCT_MARKET_RISK_EXPOSURES.N_EXPOSURE_AMT) AS  T_1351536306519_0,   (CASE  WHEN  ( ((1=1)) ) THEN 10 ELSE 11 END)  AS COND_1351536306519_10 ,  (CASE WHEN 1 = 1 THEN FCT_MARKET_RISK_EXPOSURES.n_shareholding_percent ELSE NULL END *CASE WHEN 1 = 1 THEN FCT_MARKET_RISK_EXPOSURES.n_exposure_amt ELSE NULL END ) AS EXP_1351536306519_10,(FCT_MARKET_RISK_EXPOSURES.N_EXPOSURE_AMT) AS EXP_1351536306519_11 ,(FCT_MARKET_RISK_EXPOSURES.N_EXP_MTM_VALUE) AS  T_1351536306519_1,   (CASE  WHEN  ( ((1=1)) ) THEN 20 ELSE 21 END)  AS COND_1351536306519_20 ,  (CASE WHEN 1 = 1 THEN FCT_MARKET_RISK_EXPOSURES.n_shareholding_percent ELSE NULL END *CASE WHEN 1 = 1 THEN FCT_MARKET_RISK_EXPOSURES.n_exp_mtm_value ELSE NULL END ) AS EXP_1351536306519_20,(FCT_MARKET_RISK_EXPOSURES.N_EXP_MTM_VALUE) AS EXP_1351536306519_21 ,(FCT_MARKET_RISK_EXPOSURES.N_NOTIONAL_AMT) AS  T_1351536306519_2,   (CASE  WHEN  ( ((1=1)) ) THEN 30 ELSE 31 END)  AS COND_1351536306519_30 ,  (CASE WHEN 1 = 1 THEN FCT_MARKET_RISK_EXPOSURES.n_shareholding_percent ELSE NULL END *CASE WHEN 1 = 1 THEN FCT_MARKET_RISK_EXPOSURES.n_notional_amt ELSE NULL END ) AS EXP_1351536306519_30,(FCT_MARKET_RISK_EXPOSURES.N_NOTIONAL_AMT) AS EXP_1351536306519_31 ,(FCT_MARKET_RISK_EXPOSURES.N_RESIDUAL_VALUE) AS  T_1351536306519_3,   (CASE  WHEN  ( ((1=1)) ) THEN 40 ELSE 41 END)  AS COND_1351536306519_40 ,  (CASE WHEN 1 = 1 THEN FCT_MARKET_RISK_EXPOSURES.n_shareholding_percent ELSE NULL END *CASE WHEN 1 = 1 THEN FCT_MARKET_RISK_EXPOSURES.n_residual_value ELSE NULL END ) AS EXP_1351536306519_40,(FCT_MARKET_RISK_EXPOSURES.N_RESIDUAL_VALUE) AS EXP_1351536306519_41  FROM  FCT_MARKET_RISK_EXPOSURES LEFT OUTER JOIN DIM_INSTRUMENT_TYPE ON FCT_MARKET_RISK_EXPOSURES.n_instr_type_skey = DIM_INSTRUMENT_TYPE.n_instr_type_skey LEFT OUTER JOIN DIM_MARKET_RISK_POSITION ON FCT_MARKET_RISK_EXPOSURES.n_position_skey = DIM_MARKET_RISK_POSITION.n_position_skey LEFT OUTER JOIN DIM_BANDS ON FCT_MARKET_RISK_EXPOSURES.n_time_band_skey = DIM_BANDS.n_Band_Skey AND DIM_BANDS.V_BAND_TYPE = 'MATIRBCB' LEFT OUTER JOIN DIM_BANDS DIM_MR_TIME_BAND_A ON FCT_MARKET_RISK_EXPOSURES.n_time_band_skey = DIM_MR_TIME_BAND_A.n_Band_Skey AND DIM_MR_TIME_BAND_A.V_BAND_TYPE = 'MR TIME BAND' LEFT OUTER JOIN DIM_STANDARD_UNIT ON FCT_MARKET_RISK_EXPOSURES.N_STD_UNIT_SKEY = DIM_STANDARD_UNIT.N_STD_UNIT_SKEY LEFT OUTER JOIN DIM_INDEX ON FCT_MARKET_RISK_EXPOSURES.N_INDEX_SKEY = DIM_INDEX.N_INDEX_SKEY LEFT OUTER JOIN DIM_MARKET_CENTRE ON FCT_MARKET_RISK_EXPOSURES.N_MARKET_CENTRE_SKEY = DIM_MARKET_CENTRE.N_MARKET_CENTRE_SKEY LEFT OUTER JOIN DIM_COMMODITY ON FCT_MARKET_RISK_EXPOSURES.n_commodity_skey = DIM_COMMODITY.n_commodity_skey LEFT OUTER JOIN DIM_DATES ON FCT_MARKET_RISK_EXPOSURES.n_mis_date_skey = DIM_DATES.n_date_skey LEFT OUTER JOIN DIM_RUN ON FCT_MARKET_RISK_EXPOSURES.n_run_skey = DIM_RUN.n_run_skey LEFT OUTER JOIN DIM_COUNTRY ON FCT_MARKET_RISK_EXPOSURES.n_country_skey = DIM_COUNTRY.n_country_skey LEFT OUTER JOIN DIM_GAAP ON FCT_MARKET_RISK_EXPOSURES.n_gaap_skey = DIM_GAAP.n_gaap_skey LEFT OUTER JOIN DIM_BASEL_METHODOLOGY ON FCT_MARKET_RISK_EXPOSURES.N_BASEL_METHOD_SKEY = DIM_BASEL_METHODOLOGY.N_BASEL_METHOD_SKEY LEFT OUTER JOIN DIM_BASEL_CREDIT_RATING ON FCT_MARKET_RISK_EXPOSURES.n_basel_rating = DIM_BASEL_CREDIT_RATING.n_basel_rating LEFT OUTER JOIN DIM_CURRENCY ON FCT_MARKET_RISK_EXPOSURES.v_ccy_code = DIM_CURRENCY.V_ISO_CURRENCY_CD LEFT OUTER JOIN DIM_MR_COUNTER_PARTY ON DIM_MR_COUNTER_PARTY.n_counter_party_skey = FCT_MARKET_RISK_EXPOSURES.n_mr_issuer_type_skey LEFT OUTER JOIN DIM_SEC_POOL_TYPE ON FCT_MARKET_RISK_EXPOSURES.n_sec_pool_type_skey = DIM_SEC_POOL_TYPE.n_sec_pool_type_skey LEFT OUTER JOIN DIM_STANDARD_ACCT_HEAD ON FCT_MARKET_RISK_EXPOSURES.n_std_acct_head_skey = DIM_STANDARD_ACCT_HEAD.n_std_acct_head_skey LEFT OUTER JOIN DIM_RUN_IDENTIFIER ON FCT_MARKET_RISK_EXPOSURES.n_run_identifier_skey = DIM_RUN_IDENTIFIER.n_run_identifier_skey LEFT OUTER JOIN RUN_PARAMETERS ON FCT_MARKET_RISK_EXPOSURES.n_run_parameter_setup_skey = RUN_PARAMETERS.n_run_parameter_setup_skey AND RUN_PARAMETERS.n_Run_Skey=FCT_MARKET_RISK_EXPOSURES.n_Run_Skey AND RUN_PARAMETERS.n_Date_Skey=FCT_MARKET_RISK_EXPOSURES.n_Mis_Date_Skey LEFT OUTER JOIN DIM_MR_SP_RW_CATEGORY ON DIM_MR_SP_RW_CATEGORY.n_category_skey = FCT_MARKET_RISK_EXPOSURES.n_category_skey LEFT OUTER JOIN DIM_MARKET_VARIABLES ON FCT_MARKET_RISK_EXPOSURES.n_ref_index_skey = DIM_MARKET_VARIABLES.n_mkt_var_skey LEFT OUTER JOIN FSI_IRCS ON FCT_MARKET_RISK_EXPOSURES.N_IRC_BENCHMARK_SKEY = FSI_IRCS.interest_rate_cd  LEFT OUTER JOIN FSI_CAPITAL_BANDS ON FCT_MARKET_RISK_EXPOSURES.N_CET1_CAPITAL_RATIO >= FSI_CAPITAL_BANDS.N_BAND_LOWER_BOUND_VALUE AND FCT_MARKET_RISK_EXPOSURES.N_CET1_CAPITAL_RATIO < FSI_CAPITAL_BANDS.N_BAND_UPPER_BOUND_VALUE AND FSI_CAPITAL_BANDS.N_RUN_SKEY = FCT_MARKET_RISK_EXPOSURES.N_RUN_SKEY AND FSI_CAPITAL_BANDS.N_MIS_DATE_SKEY = FCT_MARKET_RISK_EXPOSURES.N_MIS_DATE_SKEY  WHERE (1=1)  AND (DIM_DATES.D_CALENDAR_DATE=TO_DATE('20260331','yyyymmdd') AND DIM_RUN.n_run_skey = '870')  ) WHERE (   (COND_1351536306519_10 <> 11)   OR  (COND_1351536306519_20 <> 21)  OR  (COND_1351536306519_30 <> 31)  OR  (COND_1351536306519_40 <> 41) ) ) SS ON ( TT.N_ACCT_SKEY= SS.N_ACCT_SKEY AND TT.N_RUN_SKEY= SS.N_RUN_SKEY AND TT.N_GAAP_SKEY= SS.N_GAAP_SKEY AND TT.N_MIS_DATE_SKEY= SS.N_MIS_DATE_SKEY) WHEN MATCHED THEN UPDATE SET  TT.N_EXPOSURE_AMT=  CASE  WHEN  COND_1351536306519_10=10 THEN EXP_1351536306519_10 ELSE EXP_1351536306519_11 END  , TT.N_EXP_MTM_VALUE=  CASE  WHEN  COND_1351536306519_20=20 THEN EXP_1351536306519_20 ELSE EXP_1351536306519_21 END  , TT.N_NOTIONAL_AMT=  CASE  WHEN  COND_1351536306519_30=30 THEN EXP_1351536306519_30 ELSE EXP_1351536306519_31 END  , TT.N_RESIDUAL_VALUE=  CASE  WHEN  COND_1351536306519_40=40 THEN EXP_1351536306519_40 ELSE EXP_1351536306519_41 END;

    COMMIT;
    RETURN 'OK';

EXCEPTION
    WHEN OTHERS THEN
        ROLLBACK;
        RETURN 'FAIL: ' || SQLERRM;
END;
/
